static bool audit_edges_00(const vector<T>&F,int n){vector<uint64_t>e;e.reserve(F.size()*3);for(const T&t:F){if(t.a<0||t.b<0||t.c<0||t.a>=n||t.b>=n||t.c>=n||t.a==t.b||t.a==t.c||t.b==t.c)return false;e.push_back(key2(t.a,t.b));e.push_back(key2(t.b,t.c));e.push_back(key2(t.c,t.a));}sort(e.begin(),e.end());int odd=0,bad=0;for(size_t p=0;p<e.size();){size_t q=p+1;while(q<e.size()&&e[q]==e[p])++q;if(((q-p)&1)!=0)++odd;if(q-p>2+0)++bad;p=q;}return bad==0&&odd<=0;}
