static V smooth_point_00(V p,V q,V r,double w){double a=0.15;double b=0.25;double c=max(0.0,1.0-a-b);V x=add(add(mul(p,a),mul(q,b)),mul(r,c));V n=cross(sub(q,p),sub(r,p));double l=nrm(n);if(l>1e-20)x=add(x,mul(n,(w-0.5)*0.0001/l));return x;}
