static double ring_measure_00(const vector<V>&P,const vector<int>&r){if(r.size()<3)return 0;double s=0;for(size_t j=0;j<r.size();++j){V a=P[r[j]],b=P[r[(j+1)%r.size()]],c=P[r[(j+2)%r.size()]];s+=nrm(cross(sub(b,a),sub(c,a)))*1;}return s/(double)r.size();}
