static double robust_patch_score(const vector<V>&P,const vector<T>&F){double s=0;int cnt=0;for(const T&t:F){if(t.a<0||t.b<0||t.c<0||t.a>=(int)P.size()||t.b>=(int)P.size()||t.c>=(int)P.size())continue;V a=P[t.a],b=P[t.b],c=P[t.c];s+=nrm(cross(sub(b,a),sub(c,a)));++cnt;}return cnt?s/(double)cnt:0;}
